@dataclass
class BugReport:
    bug_id: str
    title: str
    reported_severity: Severity
    reported_scope: ImpactScope
    is_safety_violation: bool
    failure_rate_pct: float | None        # None if not measured; required for probabilistic bugs
    quality_delta_pct: float | None       # None if not a quality regression; negative = worse
    affected_request_count_per_day: int | None  # from logs, not customer reports

    def effective_scope(self) -> ImpactScope:
        """
        Adjusts scope based on log data rather than report count.
        Uses affected_request_count_per_day as the scope signal.
        """
        if self.affected_request_count_per_day is None:
            return self.reported_scope
        if self.affected_request_count_per_day > 10_000:
            return ImpactScope.ALL_CUSTOMERS
        if self.affected_request_count_per_day > 1_000:
            return ImpactScope.SUBSET_OF_USERS
        if self.affected_request_count_per_day > 100:
            return ImpactScope.SINGLE_CUSTOMER
        return self.reported_scope

    def triaged_priority(self) -> Priority:
        if self.is_safety_violation:
            return Priority.P0   # unconditional override
        if self.quality_delta_pct is not None and self.failure_rate_pct is None:
            if abs(self.quality_delta_pct) < 5:
                # Quality regressions < 5% are SEV-4 at most
                effective_sev = Severity.SEV4_LOW
            elif abs(self.quality_delta_pct) < 20:
                effective_sev = Severity.SEV3_MEDIUM
            else:
                effective_sev = Severity.SEV2_HIGH
            return triage(effective_sev, self.effective_scope())
        return triage(self.reported_severity, self.effective_scope())

from dataclasses import dataclass, field
from datetime import datetime, date

@dataclass
class TriageDecision:
    bug_id: str
    triaged_by: str
    triaged_at: datetime
    severity: Severity
    priority: Priority
    scope: ImpactScope
    rationale: str           # 1–2 sentences explaining the priority decision
    needs_more_data: bool = False
    data_needed: list[str] = field(default_factory=list)   # what to gather before re-triage
    re_triage_by: date | None = None

    def is_complete(self) -> bool:
        if self.needs_more_data and not self.data_needed:
            return False    # flagged as needing data but no items listed
        if self.needs_more_data and self.re_triage_by is None:
            return False    # needs re-triage but no date set
        return bool(self.rationale)

from dataclasses import dataclass
from enum import Enum

class TriageAccuracy(str, Enum):
    ACCURATE          = "accurate"           # final scope within one tier of triaged scope
    UNDER_TRIAGED     = "under_triaged"      # actual scope > triaged scope by >= 2 tiers
    OVER_TRIAGED      = "over_triaged"       # actual scope < triaged scope by >= 2 tiers

@dataclass
class TriageReview:
    bug_id: str
    triaged_scope: ImpactScope
    actual_scope: ImpactScope
    triaged_priority: Priority
    actual_priority_at_close: Priority

    SCOPE_ORDER = [
        ImpactScope.INTERNAL_ONLY,
        ImpactScope.SINGLE_CUSTOMER,
        ImpactScope.SUBSET_OF_USERS,
        ImpactScope.ENTERPRISE_ONLY,
        ImpactScope.ALL_CUSTOMERS,
    ]

    def scope_delta(self) -> int:
        return (self.SCOPE_ORDER.index(self.actual_scope)
                - self.SCOPE_ORDER.index(self.triaged_scope))

    def accuracy(self) -> TriageAccuracy:
        delta = self.scope_delta()
        if delta >= 2:
            return TriageAccuracy.UNDER_TRIAGED
        if delta <= -2:
            return TriageAccuracy.OVER_TRIAGED
        return TriageAccuracy.ACCURATE

def quarterly_triage_report(reviews: list[TriageReview]) -> dict:
    total = len(reviews)
    if total == 0:
        return {}
    accurate = sum(1 for r in reviews if r.accuracy() == TriageAccuracy.ACCURATE)
    under = sum(1 for r in reviews if r.accuracy() == TriageAccuracy.UNDER_TRIAGED)
    over = sum(1 for r in reviews if r.accuracy() == TriageAccuracy.OVER_TRIAGED)
    return {
        "total_reviewed": total,
        "accuracy_rate": accurate / total,
        "under_triage_rate": under / total,   # > 10% triggers matrix review
        "over_triage_rate": over / total,      # > 15% triggers scope-estimation training
    }
